// modules/files/module.contract.ts
import { defineContract } from 'aether';

export default defineContract({
  name: 'files',
  description: 'Handles file storage, retrieval, and deletion utilities.',

  dependencies: { modules: [] },

  exposes: {
    routes: [
      { method: 'POST', path: '/files/upload', auth: true },
      { method: 'GET',  path: '/files/:id',   auth: true },
      { method: 'DELETE', path: '/files/:id', auth: true },
    ],
    functions: ['uploadFile', 'getFile', 'deleteFile'],
    types: ['File', 'FileError'],
  },

  sideEffects: [
    'writes to: files table',
    'deletes from: file storage',
  ],

  invariants: [
    'A file must always be bound to exactly one user',
    'Deleted files must never be returned as valid',
    'File deletion must be asynchronous and non-blocking',
  ],
});

